#include <iostream>
using namespace std;
int r,a[1005][1005];
long ans=0,dp[1005][1005]={0};
int main()
{
    cin>>r;
    for(int i=1;i<=r;i++)
    {
        for(int j=1;j<=i;j++)
        {
            cin>>a[i][j];
            dp[i][j]=a[i][j]+max(dp[i-1][j],dp[i-1][j-1]);
            if(i==r) ans=max(ans,dp[i][j]); 
        }
    }
    cout<<ans;
    return 0;
}
